import { useState } from 'react';
import axios from 'axios';
import './style.css';

export const FileUploader = ({}) => {
    const [file, setFile] = useState(null);
    const [image, setImage] = useState(null);
    const onInputChange = (e) => {
        setFile(e.target.files[0])
    };

    const onSubmit = (e) => {
        e.preventDefault();
        const data = new FormData();
        data.append('file', file);
        axios.post('//ec2-54-173-51-94.compute-1.amazonaws.com/upload', data, {
            responseType: "arraybuffer"
          })
        .then((res) => {
            const base64 = btoa(
                new Uint8Array(res.data).reduce(
                  (data, byte) => data + String.fromCharCode(byte),
                  ''
                )
              )
            setImage(base64)
            document.getElementById('response').setAttribute("hidden", "")
        })
        .catch((err) => {
            document.getElementById('response').setAttribute("hidden", "hidden")
        })
    };

    return (
    <center>
     <form method="post" action="#" id="#" onSubmit={onSubmit}>
        <div class="form-group files">
        <label>Upload Your File </label>
        <input type="file" onChange={onInputChange} class="form-control"/>
        </div>
        <button>Submit</button>
     </form>
     <div>
     <img src={`data:;base64,${image}`} id = 'response' hidden/>
     </div>
    </center>)
};
